return await (async function(eda) {
  const fixtureName = '__codex_example___SCH_PrimitiveBus_modify_' + Date.now();
  const currentProject = await eda.dmt_Project.getCurrentProjectInfo();
  if (!currentProject) { throw new Error('当前没有打开工程，先补齐环境再调试这个案例。'); }
  const currentDocument = await eda.dmt_SelectControl.getCurrentDocumentInfo();
  if (!currentDocument) {
    throw new Error('当前没有活动文档，先打开一个可操作的文档页。');
  }
  if (currentDocument.documentType !== 1) {
    throw new Error('当前文档类型不是 SCHEMATIC_PAGE，请先切到 原理图图页 再运行这个案例。');
  }
  const primitiveIdCandidates = await eda.sch_PrimitiveBus.getAllPrimitiveId();
  const primitiveId = Array.isArray(primitiveIdCandidates) ? primitiveIdCandidates[0] : undefined;
  if (!primitiveId) { throw new Error('当前原理图文档里没有可用于演示的图元，先放一个对应类型的图元再运行这个案例。'); }
  const result = await eda.sch_PrimitiveBus.modify(primitiveId, 0);
  return { fixtureName, result, needsReview: true };
})(eda);
